/** @jsx jsx */
import * as React from "react"
import { jsx, Heading } from "theme-ui"
import { MDXRenderer } from "gatsby-plugin-mdx"
import Layout from "./layout"
import ItemTags from "./item-tags"
import Seo from "./seo"
import PostFooter from "./post-footer"

type Props = {
  data: {
    project: {
      slug: string
      title: string
      startDate: string
      endDate: string
      tags?: {
        name: string
        slug: string
      }[]
      tableOfContents: any
      description?: string
      canonicalUrl?: string
      body: string
      excerpt: string
      banner?: {
        childImageSharp: {
          resize: {
            src: string
          }
        }
      }
    }
  }
}

const px = [`32px`, `16px`, `8px`, `4px`]
const shadow = px.map((v) => `rgba(0, 0, 0, 0.15) 0px ${v} ${v} 0px`)

const ProjectPost = ({ data: { project } }: Props) => (
  <Layout>
    <Seo
      title={project.title}
      description={project.description ? project.description : project.excerpt}
      image={project.banner ? project.banner?.childImageSharp?.resize?.src : undefined}
      pathname={project.slug}
      canonicalUrl={project.canonicalUrl}
    />
    <Heading as="h2" variant="styles.h2">
      {project.title}
    </Heading>
    <p sx={{ color: `secondary`, mt: 3, a: { color: `secondary` }, fontSize: [1, 1, 2] }}>
      {project.tags && (
        <React.Fragment>
          {project.tags.map((tag, i) => (
            <React.Fragment key={tag.slug}>
              <span sx={{backgroundColor: `lightgray`, borderRadius: `1em`, color: `gray`, padding: `0em 0.5em`}}>
                {tag.name} 
              </span>
              {` `}
            </React.Fragment>
          ))}
          {/* <ItemTags tags={project.tags} /> */}
        </React.Fragment>
      )}
      <br/> <time>{project.startDate} {` — `} {project.endDate}</time>
    </p>
    <section
      sx={{
        my: 5,
        ".gatsby-resp-image-wrapper": { my: [4, 4, 5], boxShadow: shadow.join(`, `) },
        variant: `layout.content`,
      }}
    >
      <MDXRenderer>{project.body}</MDXRenderer>
    </section>
    {/* <PostFooter post={post} /> */}
  </Layout>
)

export default ProjectPost
