import { graphql } from "gatsby"
import ProjectPostComponent from "../../gatsby-theme-minimal-blog/@lekoarts/gatsby-theme-minimal-blog-core/components/project-post"

export default ProjectPostComponent

export const query = graphql`
  query ($slug: String!) {
    project(slug: { eq: $slug }) {
      slug
      title
      startDate(formatString: "YYYY.MM")
      endDate(formatString: "YYYY.MM")
      tags {
        name
        slug
      }
      tableOfContents
      description
      canonicalUrl
      body
      excerpt
      banner {
        childImageSharp {
          resize(width: 1200, quality: 90) {
            src
          }
        }
      }
    }
  }
`
